class Solution:
    def maximumCostSubstring(self, s, chars, vals):
        value = {}
        for i, c in enumerate(chars):
            value[c] = vals[i]
        costs = [value.get(ch, ord(ch) - ord('a') + 1) for ch in s]
        n = len(costs)
        best = 0
        for i in range(n):
            cur = 0
            for j in range(i, n):
                cur += costs[j]
                if cur > best:
                    best = cur
        return best

