class Solution:
    def maximumCostSubstring(self, s, chars, vals):
        value = {}
        for i, c in enumerate(chars):
            value[c] = vals[i]
        best = 0
        cur = 0
        for ch in s:
            v = value.get(ch, ord(ch) - ord('a') + 1)
            cur = v if cur + v < v else cur + v
            if cur > best:
                best = cur
        return best

