var maximumCostSubstring = function(s, chars, vals) {
    const value = {};
    for (let i = 0; i < chars.length; i++) {
        value[chars[i]] = vals[i];
    }
    let best = 0;
    let cur = 0;
    for (const ch of s) {
        const v = Object.prototype.hasOwnProperty.call(value, ch) ? value[ch] : (ch.charCodeAt(0) - 'a'.charCodeAt(0) + 1);
        cur = (cur + v < v) ? v : cur + v;
        if (cur > best) best = cur;
    }
    return best;
};
